import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Route, Router } from '@angular/router';
import { RequestService } from 'src/app/core/services/request.service';

@Component({
  selector: 'app-create-request',
  templateUrl: './create-request.component.html',
  styleUrls: ['./create-request.component.css']
})
export class CreateRequestComponent implements OnInit {

  requestForm : FormGroup;
  isLoading = false;
  submitter = false;
  sponsorshipType: any[] = [];
  departments : ['Marketing', 'Sales', 'HR', 'IT', 'Finance', 'Operations'];
  sponsorshipTypeList : ['Conference', 'Workshop', 'Community Event', 'Charity', 'Sports', 'Education']

  constructor(private fb: FormBuilder, private requestService: RequestService, private router: Router ){
    this.requestForm = this.fb.group({
      title: ['', [Validators.required, Validators.minLength(5), Validators.maxLength(200)]],
      department: ['', Validators.required],
      sponsorshipType: ['', Validators.required],
      eventName: ['', Validators.required],
      eventDate: ['', Validators.required],
      requestedAmount: ['', [Validators.required, Validators.min(4), Validators.max(1000000)]],
      justification: ['', [Validators.required, Validators.minLength(10)]],
      expectedBenefit: [''],
      remarks: ['']
    });
  }
  ngOnInit(): void {

  }
}
